    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormControlEventHandler(formControlStr(InventTransferParmReceive, InventTransferParmLine_QtyOverReceiveNow), FormControlEventType::Modified)]
    public static void InventTransferParmLine_QtyOverReceiveNow_OnModified(FormControl sender, FormControlEventArgs e)
    {
        FormRun                formrun                   = sender.formRun();
        FormDataSource         InventTransferParmLine_ds = sender.formRun().dataSource(formDataSourceStr(InventTransferParmReceive,InventTransferParmLine));
        InventTransferParmLine inventTransferParmLine    = InventTransferParmLine_ds.cursor();
        InventQty              overReceiveQty            = str2Num(sender.valueStr());
        InventTransferLine     inventTransferLine        = inventTransferParmLine.inventTransferLine();
        InventQty              overDeliveryQty;

        overDeliveryQty = (inventTransferLine.QtyTransfer * inventTransferLine.OverDeliveryPct / 100) + inventTransferLine.QtyTransfer;

        overDeliveryQty =  overDeliveryQty - (inventTransferLine.QtyShipped + inventTransferLine.QtyOverReceived);

        if(overDeliveryQty < overReceiveQty)
        {
            throw Error(strFmt('Only over delivery %1 percent can be allowed',inventTransferLine.OverDeliveryPct));
        }
    }

///SB, DLT, 30/04/2026
/// <summary>
/// COC of standard method to add custom BatchId
/// </summary>
public void initFromInventTable(InventTable _inventTable, InventDimId _inventDimId)
{
    next initFromInventTable(_inventTable, _inventDimId);

    if(ETGCanadaParameters::find().EnableDefaultBatchNumber == NoYes::Yes)
    {
        InventDim inventDim = InventDim::find(this.InventDimId);

        // Default BatchId
        inventDim.inventBatchId = _inventTable.ETGDefaultBatchNumber;

        this.InventDimId            = InventDim::findOrCreate(inventDim).InventDimId;
    }
}
